import { API_HOST } from '../api/api';

export default function ProductDetails({ product }) {
  if (!product) {
    return (
      <div className="details-card details-card--empty">
        Введите id товара или нажмите "Подробнее" в карточке.
      </div>
    );
  }

  const imageSrc = product.image
    ? product.image.startsWith('http')
      ? product.image
      : product.image.startsWith('/uploads/')
        ? `${API_HOST}${product.image}`
        : product.image
    : '';

  return (
    <div className="details-card">
      <h3>Информация о товаре</h3>
      <p><strong>ID:</strong> {product.id}</p>
      <p><strong>Название:</strong> {product.title}</p>
      <p><strong>Категория:</strong> {product.category}</p>
      <p><strong>Описание:</strong> {product.description}</p>
      <p><strong>Цена:</strong> {product.price} ₽</p>
      <p><strong>Остаток:</strong> {product.stock} шт.</p>

      {imageSrc ? (
        <img className="details-image" src={imageSrc} alt={product.title} />
      ) : (
        <div className="details-image details-image--placeholder">Нет изображения</div>
      )}
    </div>
  );
}
